    public static ArrayList<Token> listaErrores = new ArrayList<>();

    @Override
    public void syntax_error(Symbol s) {

        String lexema = "EOF";

        if (s.value != null) {
            lexema = s.value.toString();
        }

        String esperado = "Token inesperado";

        switch(s.sym){

            case sym.PUNTOCOMA:
                esperado = "Se esperaba ';'";
                break;

            case sym.CORCHETE_CIERRA:
                esperado = "Se esperaba ']'";
                break;

            case sym.CORCHETE_ABRE:
                esperado = "Se esperaba '['";
                break;

            case sym.LLAVE_CIERRA:
                esperado = "Se esperaba '}'";
                break;

            case sym.LLAVE_ABRE:
                esperado = "Se esperaba '{'";
                break;

            case sym.COMA:
                esperado = "Se esperaba ','";
                break;

            default:
                esperado = "Error sintáctico en la estructura";
        }

        listaErrores.add(
            new Token(
                lexema,
                s.left + 1,
                s.right + 1,
                "Sintáctico",
                esperado
            )
        );
    }

    @Override
    public void report_error(String message, Object info) {

        if(info instanceof Symbol){

            Symbol sym = (Symbol) info;

            listaErrores.add(
                new Token(
                    sym.value != null ? sym.value.toString() : "EOF",
                    sym.left + 1,
                    sym.right + 1,
                    "Sintáctico",
                    message
                )
            );
        }
    }

    @Override
    public void report_fatal_error(String message, Object info) {
        report_error(message, info);
    }


